async function execute(browser: WebFlowBrowserAPI, params: FlowParams): Promise<WebFlowResult> {
    const reservations = await browser.extractComponent<{ date: string; availableTimeSlots?: { time?: string; cssSelector: string }[] }>({
        typeName: 'BookReservationsModule',
        schema: '{ date: string; targetTime: string; availableTimeSlots?: { time?: string; cssSelector: string; }[]; numberOfPeople?: number; }'
    });
    if (!reservations || !reservations.availableTimeSlots || reservations.availableTimeSlots.length === 0) {
        return { success: false, error: 'No available time slots found on this page' };
    }
    const targetSlot = reservations.availableTimeSlots.find(
        s => s.time && s.time.toLowerCase().includes(params.time.toLowerCase())
    );
    if (!targetSlot) {
        const available = reservations.availableTimeSlots.map(s => s.time).filter(Boolean).join(', ');
        return { success: false, error: 'Time ' + params.time + ' not available. Available: ' + available };
    }
    await browser.clickAndWait(targetSlot.cssSelector);
    return { success: true, message: 'Selected reservation at ' + targetSlot.time };
}
